<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeConcession;use Illuminate\Database\Eloquent\Collection;class FeeConcessionRepository extends BaseRepository{    public function __construct(FeeConcession $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function getActiveConcessions(): Collection    {        return $this->query()->where('is_active', true)->where(function ($q) {                $q->whereNull('valid_until')->orWhere('valid_until', '>=', now());            })->get();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByConcessionType(string $type): Collection    {        return $this->findByField('concession_type', $type);    }    public function applyConcession(int $studentId, int $feeStructureId, array $data): FeeConcession    {        $data['student_id'] = $studentId;        $data['fee_structure_id'] = $feeStructureId;        return $this->create($data);    }    public function revokeConcession(int $id): bool    {        return $this->update($id, ['is_active' => false, 'revoked_at' => now()]);    }}